var ecoregions = ee.FeatureCollection("RESOLVE/ECOREGIONS/2017");
var westernGhats = ecoregions.filter(ee.Filter.or(
  ee.Filter.eq('ECO_NAME', 'South Western Ghats moist deciduous forests'),
  ee.Filter.eq('ECO_NAME', 'North Western Ghats moist deciduous forests'),
  ee.Filter.eq('ECO_NAME', 'South Western Ghats montane rain forests'),
  ee.Filter.eq('ECO_NAME', 'North Western Ghats montane rain forests')
));
var studyArea = westernGhats.geometry();
Map.centerObject(westernGhats, 7);
function coordsToFC(coordArray) {
  var features = coordArray.map(function(c) {
    return ee.Feature(ee.Geometry.Point(c[0], c[1]));
  });
  return ee.FeatureCollection(features);
}
var gtFC  = coordsToFC(gtFireCoords);
var ensFC = coordsToFC(ensFireCoords);
var tpFC = ensFC.map(function(feat) {
  var nearby = gtFC.filterBounds(feat.geometry().buffer(1000));
  return feat.set('is_tp', nearby.size().gt(0));
}).filter(ee.Filter.eq('is_tp', 1));
var fpFC = ensFC.map(function(feat) {
  var nearby = gtFC.filterBounds(feat.geometry().buffer(1000));
  return feat.set('is_fp', nearby.size().eq(0));
}).filter(ee.Filter.eq('is_fp', 1));
var fnFC = gtFC.map(function(feat) {
  var nearby = ensFC.filterBounds(feat.geometry().buffer(1000));
  return feat.set('is_fn', nearby.size().eq(0));
}).filter(ee.Filter.eq('is_fn', 1));
Map.addLayer(
  westernGhats,
  {color: '228B22'},
  '🌿 Western Ghats Boundary',
  true
);
var mod14 = ee.ImageCollection("MODIS/061/MOD14A1")
  .filterDate('2021-01-01', '2025-12-31')
  .filterBounds(studyArea);
var fireCount = mod14.select('FireMask').map(function(img) {
  return img.gte(7);
}).sum().clip(studyArea);
Map.addLayer(
  fireCount,
  {min: 0, max: 30, palette: ['FFFFFF','FFFF80','FFA500','FF4500','8B0000']},
  '🔥 MODIS Fire Density 2021-2025 (background)',
  true,
  0.5
);
var ndvi = ee.ImageCollection("MODIS/061/MOD13A2")
  .filterDate('2021-01-01', '2025-12-31')
  .filterBounds(studyArea)
  .select('NDVI').median().multiply(0.0001).clip(studyArea);
Map.addLayer(
  ndvi,
  {min: 0, max: 0.9, palette: ['CE7E45','DF923D','F1B555','FCD163','99B718','529400','207401']},
  '🌿 NDVI Median 2021-2025 (background)',
  false
);
Map.addLayer(
  gtFC,
  {color: '0000FF'},
  '🔵 Ground Truth Fire (y_true=1) — ' + gtFireCoords.length + ' pts',
  true
);
Map.addLayer(
  ensFC,
  {color: 'FF0000'},
  '🔴 Ensemble Predicted Fire — ' + ensFireCoords.length + ' pts',
  true
);
Map.addLayer(
  tpFC,
  {color: 'FFD700'},
  '🟡 True Positives (GT=1 & Ens=1)',
  true
);
Map.addLayer(
  fpFC,
  {color: 'FF6600'},
  '🟠 False Positives (Ens=1 but GT=0)',
  false
);
Map.addLayer(
  fnFC,
  {color: '9400D3'},
  '🟣 False Negatives (GT=1 but Ens=0)',
  false
);
var legend = ui.Panel({
  style: {
    position: 'bottom-left',
    padding: '8px 12px',
    backgroundColor: 'rgba(255,255,255,0.9)'
  }
});
var legendTitle = ui.Label({
  value: 'AGFE-Fire v4  |  ENSEMBLE Predictions (Block 4 Test)',
  style: {fontWeight: 'bold', fontSize: '13px', margin: '0 0 6px 0'}
});
legend.add(legendTitle);
var items = [
  {color: '0000FF', label: 'Ground Truth Fire  (' + gtFireCoords.length + ' pts)'},
  {color: 'FF0000', label: 'Ensemble Predicted  (' + ensFireCoords.length + ' pts)'},
  {color: 'FFD700', label: 'True Positives  (GT ∩ Ens)'},
  {color: 'FF6600', label: 'False Positives  (Ens only)'},
  {color: '9400D3', label: 'False Negatives  (GT only, missed)'}
];
items.forEach(function(item) {
  var row = ui.Panel({
    layout: ui.Panel.Layout.flow('horizontal'),
    style: {margin: '2px 0'}
  });
  var dot = ui.Label({
    style: {
      backgroundColor: '#' + item.color,
      padding: '6px',
      margin: '0 6px 0 0',
      border: '1px solid #333'
    }
  });
  var lbl = ui.Label({value: item.label, style: {fontSize: '11px', margin: '0'}});
  row.add(dot);
  row.add(lbl);
  legend.add(row);
});
legend.add(ui.Label({
  value: '─────────────────────────',
  style: {fontSize: '10px', margin: '4px 0 2px'}
}));
legend.add(ui.Label({
  value: 'Ensemble: RF(0.45) + XGB(0.05) + LGB(0.50)',
  style: {fontSize: '11px', color: '#555'}
}));
legend.add(ui.Label({
  value: 'Accuracy: 94.63% | F1: 0.9164 | AUC: 0.9758',
  style: {fontSize: '11px', color: '#555'}
}));
legend.add(ui.Label({
  value: 'Test Set: Block 4 (2021-2025)',
  style: {fontSize: '11px', color: '#555'}
}));
legend.add(ui.Label({
  value: '⚙️  Toggle layers via Layers panel (top-right)',
  style: {fontSize: '10px', color: '#888', margin: '4px 0 0'}
}));
Map.add(legend);
print('');
print('╔══════════════════════════════════════════════════════╗');
print('║  AGFE-Fire v4  |  ENSEMBLE vs Ground Truth          ║');
print('╚══════════════════════════════════════════════════════╝');
print('');
print('📍 Study Area  : Western Ghats (4 ecoregions)');
print('📅 Test Block  : Block 4 — 2021 to 2025');
print('🤖 Model       : Stacking Ensemble (RF + XGB + LGB)');
print('🏆 Weights     : RF=0.45, XGB=0.05, LGB=0.50');
print('📊 Accuracy    : 94.63% (beats RF 93.68% by +0.96pp)');
print('');
print('Ground Truth fire pixels   : ' + gtFireCoords.length + ' pts (BLUE)');
print('Ensemble Predicted fires   : ' + ensFireCoords.length + ' pts (RED)');
print('');
print('Layers available:');
print('  🔵 Ground Truth Fire      — always blue, reference');
print('  🔴 Ensemble Predicted     — combined model output');
print('  🟡 True Positives         — both agree on fire');
print('  🟠 False Positives        — Ensemble detected, not GT');
print('  🟣 False Negatives        — GT fire, Ensemble missed');
print('  🔥 MODIS Fire Density     — background heatmap');
print('  🌿 NDVI Median            — vegetation context');
